(() => {
  "use strict";

  const rawHtml = atob('');

  if (typeof DOMParser === "undefined") {
    document.documentElement.textContent = rawHtml;
    return;
  }

  const parser = new DOMParser();
  const parsed = parser.parseFromString(rawHtml, "text/html");

  // Buang node berbahaya agar tidak ada script/objek eksternal yang dijalankan.
  const blockedSelectors = [
    "script",
    "iframe",
    "object",
    "embed",
    "base",
    "meta[http-equiv='refresh']",
    "link"
  ];
  parsed.querySelectorAll(blockedSelectors.join(",")).forEach((node) => node.remove());

  const urlAttrs = new Set(["src", "href", "xlink:href", "action", "formaction", "poster", "data"]);
  const isDangerousUrl = (value) => /^\s*(javascript:|vbscript:|data:(?!image\/))/i.test(String(value || ""));
  const isUnsafeUrl = (value) => {
    const v = String(value || "").trim().toLowerCase();
    if (!v) return false;
    if (v.startsWith("#")) return false;
    if (v.startsWith("/") || v.startsWith("./") || v.startsWith("../")) return false;
    if (v.startsWith("data:image/")) return false;
    if (v.startsWith("mailto:") || v.startsWith("tel:")) return false;
    return /^([a-z][a-z0-9+.-]*:|\/\/)/.test(v);
  };

  parsed.querySelectorAll("*").forEach((el) => {
    for (const attr of Array.from(el.attributes)) {
      const name = attr.name.toLowerCase();
      const value = attr.value;

      if (name.startsWith("on")) {
        el.removeAttribute(attr.name);
        continue;
      }

      if (name === "srcset") {
        if (/(^|,)\s*(https?:|\/\/|javascript:|data:(?!image\/))/i.test(value)) {
          el.removeAttribute(attr.name);
        }
        continue;
      }

      if (urlAttrs.has(name)) {
        // Pertahankan link <a href="..."> agar CTA tetap berfungsi,
        // tapi tetap blokir protocol URL yang eksplisit berbahaya.
        if (name === "href" && el.tagName.toLowerCase() === "a") {
          if (isDangerousUrl(value)) {
            el.removeAttribute(attr.name);
          }
          continue;
        }

        if (isUnsafeUrl(value)) {
          el.removeAttribute(attr.name);
          continue;
        }
      }

      if (name === "style" && /url\s*\(\s*['"]?\s*(https?:|\/\/)/i.test(value)) {
        el.removeAttribute(attr.name);
      }
    }
  });

  const csp = parsed.createElement("meta");
  csp.setAttribute("http-equiv", "Content-Security-Policy");
  csp.setAttribute(
    "content",
    "default-src 'self' data: blob:; style-src 'self' 'unsafe-inline'; script-src 'none'; connect-src 'none'; frame-src 'none'; object-src 'none';"
  );
  if (parsed.head.firstChild) {
    parsed.head.insertBefore(csp, parsed.head.firstChild);
  } else {
    parsed.head.appendChild(csp);
  }

  
  // Kosongkan head dan body saat ini
  while (document.head.firstChild) { document.head.removeChild(document.head.firstChild); }
  while (document.body.firstChild) { document.body.removeChild(document.body.firstChild); }

  // Pindahkan node secara perlahan untuk menghindari bug iOS innerHTML CSS tidak terpasang
  Array.from(parsed.head.childNodes).forEach(node => {
     if (node.tagName && node.tagName.toLowerCase() === 'script') {
        const newScript = document.createElement('script');
        newScript.text = node.textContent;
        document.head.appendChild(newScript);
     } else {
        document.head.appendChild(node.cloneNode(true));
     }
  });

  Array.from(parsed.body.childNodes).forEach(node => {
     document.body.appendChild(node.cloneNode(true));
  });

})();
